#include <stdio.h>

void rotateClockwise(int a[][1000], int n){
    // transpose
    for(int i=0;i<n;i++){
        for(int j=i+1;j<n;j++){
            int tmp=a[i][j];
            a[i][j]=a[j][i];
            a[j][i]=tmp;
        }
    }
    // reverse each row
    for(int i=0;i<n;i++){
        for(int j=0;j<n/2;j++){
            int tmp=a[i][j];
            a[i][j]=a[i][n-1-j];
            a[i][n-1-j]=tmp;
        }
    }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int mat[1000][1000];
        for(int i=0;i<N;i++)
            for(int j=0;j<N;j++)
                scanf("%d",&mat[i][j]);
        rotateClockwise(mat,N);
        for(int i=0;i<N;i++){
            for(int j=0;j<N;j++){
                printf("%d",mat[i][j]);
                if(j+1<N) printf(" ");
            }
            printf("\n");
        }
    }
    return 0;
}

