#include <bits/stdc++.h>
using namespace std;

void rotateClockwise(vector<vector<int>>& a){
    int n=a.size();
    // transpose
    for(int i=0;i<n;i++)
        for(int j=i+1;j<n;j++)
            swap(a[i][j],a[j][i]);
    // reverse each row
    for(int i=0;i<n;i++)
        reverse(a[i].begin(),a[i].end());
}

