import java.io.*;
import java.util.*;

public class Main {
    private static void rotateClockwise(int[][] a){
        int n=a.length;
        // transpose
        for(int i=0;i<n;i++){
            for(int j=i+1;j<n;j++){
                int tmp=a[i][j];
                a[i][j]=a[j][i];
                a[j][i]=tmp;
            }
        }
        // reverse each row
        for(int i=0;i<n;i++){
            int l=0, r=n-1;
            while(l<r){
                int tmp=a[i][l];
                a[i][l]=a[i][r];
                a[i][r]=tmp;
                l++; r--;
            }
        }
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N=Integer.parseInt(br.readLine().trim());
            int[][] mat=new int[N][N];
            for(int i=0;i<N;i++){
                StringTokenizer st=new StringTokenizer(br.readLine());
                for(int j=0;j<N;j++) mat[i][j]=Integer.parseInt(st.nextToken());
            }
            rotateClockwise(mat);
            for(int i=0;i<N;i++){
                for(int j=0;j<N;j++){
                    out.append(mat[i][j]);
                    if(j+1<N) out.append(' ');
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

